void flushed_printf(const char* format, ...) {
    va_list args;
    va_start(args, format);
    vprintf(format, args);
    va_end(args);
    fflush(stdout);
}

void show_progress_init(int length) {
    flushed_printf("[");
    for (int i = 0; i < length; i++) flushed_printf(" ");
    flushed_printf("]");
    for (int i = 0; i <= length; i++) flushed_printf("\b");
}

void show_progress_step(int domove, char newchar) {
    flushed_printf("%c", newchar);
    if (!domove) flushed_printf("\b");
}

void show_progress_done(void) { flushed_printf("\n"); }

template <int N, typename F>
double benchmark(F&& f) {
    double sum = 0.0;
    for (int i = 0; i < N; i++) sum += f();
    return sum / (double)N;
}

static bool IsDPSupported(void) {
    cudaDeviceProp prop = GetDeviceProperties();
    return (prop.major > 1) || (prop.major == 1 && prop.minor >= 3);
}

template <typename T>
struct DevOps;

template <>
struct DevOps<int> {
    __device__ static __forceinline__ int zero() { return 0; }
    __device__ static __forceinline__ int minus_one() { return -1; }
    __device__ static __forceinline__ int add(int a, int b) { return a + b; }
    __device__ static __forceinline__ int mul(int a, int b) { return a * b; }
    __device__ static __forceinline__ bool is_equal(int a, int b) { return a == b; }
};

template <>
struct DevOps<float> {
    __device__ static __forceinline__ float zero() { return 0.0f; }
    __device__ static __forceinline__ float minus_one() { return -1.0f; }
    __device__ static __forceinline__ float add(float a, float b) { return a + b; }
    __device__ static __forceinline__ float mul(float a, float b) { return a * b; }
    __device__ static __forceinline__ bool is_equal(float a, float b) { return a == b; }
};

template <>
struct DevOps<double> {
    __device__ static __forceinline__ double zero() { return 0.0; }
    __device__ static __forceinline__ double minus_one() { return -1.0; }
    __device__ static __forceinline__ double add(double a, double b) { return a + b; }
    __device__ static __forceinline__ double mul(double a, double b) { return a * b; }
    __device__ static __forceinline__ bool is_equal(double a, double b) { return a == b; }
};

template <>
struct DevOps<__half2> {
    __device__ static __forceinline__ __half2 zero() {
        return __float2half2_rn(0.0f);
    }
    __device__ static __forceinline__ __half2 minus_one() {
        return __float2half2_rn(-1.0f);
    }
    __device__ static __forceinline__ __half2 add(__half2 a, __half2 b) {
        float al = __half2float(__low2half(a));
        float ah = __half2float(__high2half(a));
        float bl = __half2float(__low2half(b));
        float bh = __half2float(__high2half(b));
        return __floats2half2_rn(al + bl, ah + bh);
    }
    __device__ static __forceinline__ __half2 mul(__half2 a, __half2 b) {
        float al = __half2float(__low2half(a));
        float ah = __half2float(__high2half(a));
        float bl = __half2float(__low2half(b));
        float bh = __half2float(__high2half(b));
        return __floats2half2_rn(al * bl, ah * bh);
    }
    __device__ static __forceinline__ bool is_equal(__half2 a, __half2 b) {
        return __half2float(__low2half(a)) == __half2float(__low2half(b)) &&
               __half2float(__high2half(a)) == __half2float(__high2half(b));
    }
};

template <typename T, bool BLOCK_STRIDED>
__global__ void benchmark_kernel(T seed,
                                 T* g_data,
                                 long size,
                                 unsigned int compute_iters,
                                 unsigned int elements_per_thread,
                                 unsigned int fusion_degree) {
    const unsigned int blockSize = blockDim.x;

    const long stride = BLOCK_STRIDED ? (long)blockSize
                                      : (long)blockSize * (long)gridDim.x;
    const long idx = BLOCK_STRIDED
                         ? (long)blockIdx.x * (long)blockSize * (long)elements_per_thread +
                               (long)threadIdx.x
                         : (long)blockIdx.x * (long)blockSize + (long)threadIdx.x;
    const long big_stride =
        (long)gridDim.x * (long)blockSize * (long)elements_per_thread;

    T tmps[kMaxElementsPerThread];

    for (unsigned int k = 0; k < fusion_degree; k++) {
#pragma unroll
        for (unsigned int j = 0; j < kMaxElementsPerThread; j++) {
            if (j < elements_per_thread) {
                const long index = idx + (long)j * stride + (long)k * big_stride;
                if (index < size) {
                    tmps[j] = g_data[index];
                    for (unsigned int i = 0; i < compute_iters; i++) {
                        tmps[j] = DevOps<T>::add(DevOps<T>::mul(tmps[j], tmps[j]), seed);
                    }
                } else {
                    tmps[j] = DevOps<T>::zero();
                }
            }
        }

        T sum = DevOps<T>::zero();
#pragma unroll
        for (unsigned int j = 0; j + 1 < kMaxElementsPerThread; j += 2) {
            if (j + 1 < elements_per_thread) {
                sum = DevOps<T>::add(sum, DevOps<T>::mul(tmps[j], tmps[j + 1]));
            }
        }

        const long out_index = idx + (long)k * big_stride;
        if (out_index < size && DevOps<T>::is_equal(sum, DevOps<T>::minus_one())) {
            g_data[out_index] = sum;
        }
    }
}

template <typename LaunchFn>
double get_cuda_event_duration(LaunchFn&& launch) {
    cudaEvent_t ev_start, ev_stop;
    CUDA_SAFE_CALL(cudaEventCreate(&ev_start));
    CUDA_SAFE_CALL(cudaEventCreate(&ev_stop));
    CUDA_SAFE_CALL(cudaEventRecord(ev_start, 0));
    launch();
    CUDA_SAFE_CALL(cudaGetLastError());
    CUDA_SAFE_CALL(cudaEventRecord(ev_stop, 0));
    CUDA_SAFE_CALL(cudaEventSynchronize(ev_stop));
    float ms = 0.0f;
    CUDA_SAFE_CALL(cudaEventElapsedTime(&ms, ev_start, ev_stop));
    CUDA_SAFE_CALL(cudaEventDestroy(ev_start));
    CUDA_SAFE_CALL(cudaEventDestroy(ev_stop));
    return (double)ms;
}

template <typename LaunchFn>
double get_os_duration(LaunchFn&& launch) {
    auto ts_start = std::chrono::high_resolution_clock::now();
    launch();
    CUDA_SAFE_CALL(cudaGetLastError());
    CUDA_SAFE_CALL(cudaDeviceSynchronize());
    auto ts_end = std::chrono::high_resolution_clock::now();
    return std::chrono::duration<double, std::milli>(ts_end - ts_start).count();
}

template <typename T, bool BLOCK_STRIDED>
void launch_kernel(T seed,
                   void* cbuffer,
                   long size,
                   size_t workgroupsize,
                   unsigned int elements_per_wi,
                   unsigned int fusion_degree,
                   unsigned int compute_iters) {
    const long compute_grid_size = size / (long)elements_per_wi / (long)fusion_degree;
    const long num_blocks = compute_grid_size / (long)workgroupsize;
    if (num_blocks <= 0) return;
    benchmark_kernel<T, BLOCK_STRIDED><<<static_cast<unsigned int>(num_blocks),
                                         static_cast<unsigned int>(workgroupsize)>>>(
        seed, reinterpret_cast<T*>(cbuffer), size, compute_iters, elements_per_wi,
        fusion_degree);
}

template <bool BLOCK_STRIDED>
void runbench_warmup(void* cbuffer, long size, size_t workgroupsize) {
    const long reduced_grid_size = size / 256;
    const long num_blocks = reduced_grid_size / (long)workgroupsize;
    if (num_blocks <= 0) return;
    const int seed = 1;
    benchmark_kernel<int, BLOCK_STRIDED><<<static_cast<unsigned int>(num_blocks),
                                           static_cast<unsigned int>(workgroupsize)>>>(
        seed, reinterpret_cast<int*>(cbuffer), size, 0, 1, 1);
    CUDA_SAFE_CALL(cudaGetLastError());
}

void runbench(const int compute_iterations[],
              unsigned int krn_idx,
              void* cbuffer,
              long size,
              size_t workgroupsize,
              unsigned int elements_per_wi,
              unsigned int fusion_degree,
              bool use_os_timer,
              bool enable_dp,
              bool enable_hp,
              bool block_strided) {
    const long compute_grid_size = size / elements_per_wi / fusion_degree;
    const int current_compute_iterations = compute_iterations[krn_idx];
    const long long computations =
        (elements_per_wi * (long long)compute_grid_size +
         (2LL * elements_per_wi * current_compute_iterations) *
             (long long)compute_grid_size) *
        fusion_degree;
    const long long memoryoperations = size;
    constexpr int total_bench_iterations = 3;

    auto time_float = [&]() {
        const float seed_f = 1.0f;
        if (use_os_timer) {
            return get_os_duration([&]() {
                if (block_strided)
                    launch_kernel<float, true>(seed_f, cbuffer, size, workgroupsize,
                                               elements_per_wi, fusion_degree,
                                               current_compute_iterations);
                else
                    launch_kernel<float, false>(seed_f, cbuffer, size, workgroupsize,
                                                elements_per_wi, fusion_degree,
                                                current_compute_iterations);
            });
        } else {
            return get_cuda_event_duration([&]() {
                if (block_strided)
                    launch_kernel<float, true>(seed_f, cbuffer, size, workgroupsize,
                                               elements_per_wi, fusion_degree,
                                               current_compute_iterations);
                else
                    launch_kernel<float, false>(seed_f, cbuffer, size, workgroupsize,
                                                elements_per_wi, fusion_degree,
                                                current_compute_iterations);
            });
        }
    };

    auto time_double = [&]() {
        const double seed_d = 1.0;
        if (!enable_dp) return 0.0;
        if (use_os_timer) {
            return get_os_duration([&]() {
                if (block_strided)
                    launch_kernel<double, true>(seed_d, cbuffer, size, workgroupsize,
                                                elements_per_wi, fusion_degree,
                                                current_compute_iterations);
                else
                    launch_kernel<double, false>(seed_d, cbuffer, size, workgroupsize,
                                                 elements_per_wi, fusion_degree,
                                                 current_compute_iterations);
            });
        } else {
            return get_cuda_event_duration([&]() {
                if (block_strided)
                    launch_kernel<double, true>(seed_d, cbuffer, size, workgroupsize,
                                                elements_per_wi, fusion_degree,
                                                current_compute_iterations);
                else
                    launch_kernel<double, false>(seed_d, cbuffer, size, workgroupsize,
                                                 elements_per_wi, fusion_degree,
                                                 current_compute_iterations);
            });
        }
    };

    auto time_half = [&]() {
        const __half2 seed_h = __float2half2_rn(1.0f);
        if (!enable_hp) return 0.0;
        if (use_os_timer) {
            return get_os_duration([&]() {
                if (block_strided)
                    launch_kernel<__half2, true>(seed_h, cbuffer, size, workgroupsize,
                                                 elements_per_wi, fusion_degree,
                                                 current_compute_iterations);
                else
                    launch_kernel<__half2, false>(seed_h, cbuffer, size, workgroupsize,
                                                  elements_per_wi, fusion_degree,
                                                  current_compute_iterations);
            });
        } else {
            return get_cuda_event_duration([&]() {
                if (block_strided)
                    launch_kernel<__half2, true>(seed_h, cbuffer, size, workgroupsize,
                                                 elements_per_wi, fusion_degree,
                                                 current_compute_iterations);
                else
                    launch_kernel<__half2, false>(seed_h, cbuffer, size, workgroupsize,
                                                  elements_per_wi, fusion_degree,
                                                  current_compute_iterations);
            });
        }
    };

    auto time_int = [&]() {
        const int seed_i = 1;
        if (use_os_timer) {
            return get_os_duration([&]() {
                if (block_strided)
                    launch_kernel<int, true>(seed_i, cbuffer, size, workgroupsize,
                                             elements_per_wi, fusion_degree,
                                             current_compute_iterations);
                else
                    launch_kernel<int, false>(seed_i, cbuffer, size, workgroupsize,
                                              elements_per_wi, fusion_degree,
                                              current_compute_iterations);
            });
        } else {
            return get_cuda_event_duration([&]() {
                if (block_strided)
                    launch_kernel<int, true>(seed_i, cbuffer, size, workgroupsize,
                                             elements_per_wi, fusion_degree,
                                             current_compute_iterations);
                else
                    launch_kernel<int, false>(seed_i, cbuffer, size, workgroupsize,
                                              elements_per_wi, fusion_degree,
                                              current_compute_iterations);
            });
        }
    };

    double kernel_time_mad_sp = benchmark<total_bench_iterations>(time_float);
    double kernel_time_mad_dp = benchmark<total_bench_iterations>(time_double);
    double kernel_time_mad_hp = benchmark<total_bench_iterations>(time_half);
    double kernel_time_mad_int = benchmark<total_bench_iterations>(time_int);

    printf(
        "         %4d,   %8.3f,%8.2f,%8.2f,%7.2f,   %8.3f,%8.2f,%8.2f,%7.2f,   "
        "%8.3f,%8.2f,%8.2f,%7.2f,  %8.3f,%8.2f,%8.2f,%7.2f\n",
        current_compute_iterations,
        ((double)computations) / ((double)memoryoperations * sizeof(float)),
        kernel_time_mad_sp,
        ((double)computations) / kernel_time_mad_sp * 1000. /
            (double)(1000 * 1000 * 1000),
        ((double)memoryoperations * sizeof(float)) / kernel_time_mad_sp * 1000. /
            (1000. * 1000. * 1000.),
        ((double)computations) / ((double)memoryoperations * sizeof(double)),
        kernel_time_mad_dp,
        ((double)computations) / kernel_time_mad_dp * 1000. /
            (double)(1000 * 1000 * 1000),
        ((double)memoryoperations * sizeof(double)) / kernel_time_mad_dp * 1000. /
            (1000. * 1000. * 1000.),
        ((double)2 * computations) /
            ((double)memoryoperations * sizeof(__half2)),
        kernel_time_mad_hp,
        ((double)2 * computations) / kernel_time_mad_hp * 1000. /
            (double)(1000 * 1000 * 1000),
        ((double)memoryoperations * sizeof(__half2)) / kernel_time_mad_hp *
            1000. / (1000. * 1000. * 1000.),
        ((double)computations) / ((double)memoryoperations * sizeof(int)),
        kernel_time_mad_int,
        ((double)computations) / kernel_time_mad_int * 1000. /
            (double)(1000 * 1000 * 1000),
        ((double)memoryoperations * sizeof(int)) / kernel_time_mad_int * 1000. /
            (1000. * 1000. * 1000.));
}

extern "C" void mixbenchGPU(double* c, long size) {
    const char* benchtype = kBlockStrided ? "Workgroup" : "NDRange";
    printf("Workgroup size:         %zu\n", kWorkgroupSize);
    printf("Elements per workitem:  %u\n", kElementsPerThread);
    printf("Workitem fusion degree: %u\n", kFusionDegree);
    printf("Workitem stride:        %s\n", benchtype);
    printf("Buffer allocation:      Device allocated\n");
    printf("Timer:                  %s\n", kUseOsTimer ? "OS based" : "CUDA event based");

    const bool enable_dp = IsDPSupported();
    if (!enable_dp)
        printf("Warning:                Double precision computations are not supported\n");
    const bool enable_hp = IsFP16Supported();
    if (!enable_hp)
        printf("Warning:                Half precision computations are not supported\n");

    void* c_buffer = nullptr;
    CUDA_SAFE_CALL(cudaMalloc(&c_buffer, (size_t)size * sizeof(double)));

    CUDA_SAFE_CALL(cudaMemset(c_buffer, 0, (size_t)size * sizeof(int)));

    printf("Loading kernel source file...\n");
    printf("Precompilation of kernels... ");
    show_progress_init(compute_iterations_len);
    for (int i = 0; i < compute_iterations_len; i++) {
        show_progress_step(0, '\\');
        show_progress_step(0, '|');
        if (enable_dp) show_progress_step(0, '/');
        if (enable_hp) show_progress_step(0, '-');
        show_progress_step(1, '>');
    }
    show_progress_done();

    if (kBlockStrided)
        runbench_warmup<true>(c_buffer, size, kWorkgroupSize);
    else
        runbench_warmup<false>(c_buffer, size, kWorkgroupSize);

    CUDA_SAFE_CALL(cudaDeviceSynchronize());

    printf(
        "----------------------------------------------------------------------------- CSV data "
        "-----------------------------------------------------------------------------"
        "-----\n");
    printf(
        "Experiment ID, Single Precision ops,,,,              Double precision "
        "ops,,,,              Half precision ops,,,,                Integer "
        "operations,,, \n");
    printf(
        "Compute iters, Flops/byte, ex.time,  GFLOPS, GB/sec, Flops/byte, "
        "ex.time,  GFLOPS, GB/sec, Flops/byte, ex.time,  GFLOPS, GB/sec, "
        "Iops/byte, ex.time,   GIOPS, GB/sec\n");

    for (int i = 0; i < compute_iterations_len; i++) {
        runbench(compute_iterations, i, c_buffer, size, kWorkgroupSize,
                 kElementsPerThread, kFusionDegree, kUseOsTimer, enable_dp,
                 enable_hp, kBlockStrided);
    }

    printf(
        "------------------------------------------------------------------------"
        "------------------------------------------------------------------------"
        "--------------------\n");

    CUDA_SAFE_CALL(cudaMemcpy(c, c_buffer, (size_t)size * sizeof(double),
                              cudaMemcpyDeviceToHost));

    CUDA_SAFE_CALL(cudaFree(c_buffer));
}
